const coordKey = ([x, y]: Cell): string => `${x},${y}`;

type NeighborTally = { cell: Cell; key: string; count: number };

export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(coordKey));
  const tallies = new Map<string, NeighborTally>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = coordKey(cell);
      const tally = tallies.get(key) ?? { cell, key, count: 0 };
      tally.count++;
      tallies.set(key, tally);
    }
  }

  const survives = ({ key, count }: NeighborTally): boolean =>
    count === 3 || (count === 2 && liveKeys.has(key));

  const result: Cell[] = [];
  for (const tally of tallies.values()) {
    if (survives(tally)) result.push(tally.cell);
  }
  return result;
}
